def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for x in range(8, 2, -2):
                for y in range(2, x + 5, 2):
                    factor = ((ratio - x) ** 6) / (x * y * 1.1 + 2)
                    priority += np.sin(ratio * y / (x + 2)) * factor
                    for z in range(1, 4):
                        priority += np.cos(ratio * y * z / (x + 3)) * ((ratio - z)**3) / (z + 1)
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 2
            if bin_cap < item * 0.3:
                priority += np.sqrt(item * bin_cap) * 7
            else:
                priority -= np.log1p(ratio) * 9
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5, 2):
                for q in range(2, p + 4, 2):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 1.5)
                    priority += np.tanh(term) * 1.4
                for r in range(1, 3):
                    priority -= np.sin(ratio * r + i) * 0.5 / (p + r)
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                inner = ((ratio - 2) ** r) / (r * 2.1)
                s += inner * np.cos(r * ratio * 1.2) + inner * np.sin(ratio / (r + 0.5))
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 6
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 0.7) * np.sin(n * ratio * 1.5)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 6):
                if (i + m) % 2 == 0:
                    priority += np.sin(m * ratio * i * 1.3) * ((ratio - 0.9) ** m) / m
                else:
                    priority -= np.cos(m * ratio * i * 1.3) * ((ratio - 0.9) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                sign = 1 if j % 2 == 0 else -1
                priority += sign * ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 2.2) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7.5
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
            if (i * idx) % 5 == 0:
                priority += np.sin(ratio * i * idx) * 0.2
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
